const now = new Date();
const todayMonth = now.getMonth() + 1;
const todayDay = now.getDate();

function getFirst(arr) {
  return Array.isArray(arr) && arr.length ? arr[0] : null;
}

function cleanPhone(value) {
  if (!value) return '';
  const cleaned = String(value).replace(/[^\d+]/g, '');
  if (cleaned.startsWith('00')) return '+' + cleaned.slice(2);
  return cleaned;
}

function parseBirthday(birthdays) {
  if (!Array.isArray(birthdays) || birthdays.length === 0) return { month: null, day: null };
  const b = birthdays[0] || {};
  const d = b.date || {};
  return {
    month: Number(d.month || b.month || 0) || null,
    day: Number(d.day || b.day || 0) || null,
  };
}

return items.map((item) => {
  const j = item.json;
  const name = getFirst(j.names) || {};
  const emailObj = getFirst(j.emailAddresses) || {};
  const phoneObj = getFirst(j.phoneNumbers) || {};
  const birthday = parseBirthday(j.birthdays);

  const firstName = name.givenName || name.displayName || '';
  const lastName = name.familyName || '';
  const fullName = [firstName, lastName].filter(Boolean).join(' ').trim() || 'Friend';
  const email = (emailObj.value || '').trim();
  const whatsappNumber = cleanPhone(phoneObj.value || '');

  const telegramChatId = (j.biographies && j.biographies[0] && j.biographies[0].value)
    ? String(j.biographies[0].value).trim()
    : '';

  const hasBirthdayToday = birthday.month === todayMonth && birthday.day === todayDay;
  const hasEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const hasWhatsapp = /^\+?[1-9]\d{7,14}$/.test(whatsappNumber);
  const hasTelegram = /^-?\d+$/.test(telegramChatId);

  return {
    json: {
      ...j,
      firstName,
      lastName,
      fullName,
      email,
      whatsappNumber,
      telegramChatId,
      birthdayMonth: birthday.month,
      birthdayDay: birthday.day,
      hasBirthdayToday,
      hasEmail,
      hasWhatsapp,
      hasTelegram,
    }
  };
}).filter(item => item.json.hasBirthdayToday);

const src = $input.first().json;
const subject = src.subject || `Happy Birthday ${src.firstName || src.fullName || ''}`.trim();
const emailMessage = src.emailMessage || `Wishing you a wonderful birthday, ${src.firstName || src.fullName || 'Friend'}! Have a fantastic day ahead.`;
const shortMessage = src.shortMessage || `Happy Birthday ${src.firstName || ''}! Wishing you a fantastic day!`.trim();

return [{
  json: {
    ...src,
    subject,
    emailMessage,
    shortMessage
  }
}];

return items.map(item => {
  const j = item.json;
  const lines = [
    '🎂 Birthday automation completed',
    '',
    `Contact: ${j.fullName}`,
    `Email: ${j.emailStatus || 'Unknown'}`,
    `WhatsApp: ${j.whatsappStatus || 'Unknown'}`,
    `Telegram: ${j.telegramStatus || 'Unknown'}`
  ];

  return {
    json: {
      ...j,
      slackText: lines.join('\n')
    }
  };
});
